---播放特效
---@class LBattleSkillActEffect
local LBattleSkillActEffect = classX("LBattleSkillActEffect", nil)


---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
function LBattleSkillActEffect.FormatEveryTargetEff(player,effData)
    local obj = player:GetTargetAtkUnitView()
    if not obj then return end

    local skillHurtList = player:GetSkillHurtDataList() --技能伤害表现
    local dataList = {}
    local index = 1
    for k,v in ipairs(skillHurtList) do
        for k1,v1 in ipairs(v) do
            local tempData = {
                tarId = v1.hitHurt.eId,
                hurtDataType = 3, --单独多次飘字
                hurtDataIndex = index, --子弹序号
            }
            table.insert(dataList, tempData)
            index = index+1
        end
    end
    return dataList
end

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActEffect.Execute(player,effData, playState)
    local effRes = effData.effRes --光效名字

    local playNum = tonumber(effData.playNum)
    if playNum and playNum == 1 then
        FireEvent(EventNames.ON_LOAD_BATTLEWND_EFFECT,{
            preload = false,
            effId = effRes,
            resType = 1,
            effData = effData,
            state = 1,
        })
        return
    end

    local _recordPosOnHookIdMap = player:GetRecordPosOnHookIdMap()
    local _isPosOnHook = player:IsPosOnHook()
    local _viewMgr = player:GetViewMgr()

    local playTime = effData.playTime --光效持续时间
    local dissipateTime = effData.dissipateTime --光效消散时间
    local offset = effData.effOffsetStart --偏移
    local excursionIObject = effData.excursionIObject

    local dataList = {}
    local effTarget = effData.effTarget
    if playState.isTarBullet then
        local tempData = player:FormatEffectData(effData,playState)
        if tempData then table.insert(dataList,tempData) end
    else
        local hitHeroNum = 0
        local hitHeros = player:GetHitHeroes() or {}
        for k,v in pairs(hitHeros) do
            hitHeroNum = hitHeroNum + 1
        end
        local isHasMoreHitHero = hitHeroNum > 1

        if effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
            local effDataList = LBattleSkillActEffect.FormatEveryTargetEff(player, effData)
            if effDataList then
                if isHasMoreHitHero then
                    for k,v in ipairs(effDataList) do
                        local tempData = player:FormatEffectData(effData,v)
                        if tempData then table.insert(dataList,tempData) end
                    end
                else
                    local selData = nil
                    for i,v in ipairs(effDataList) do
                        if v.tarId then
                            selData = v
                            break
                        end
                    end
                    if selData then
                        local tempData = player:FormatEffectData(effData,selData)
                        if tempData then table.insert(dataList,tempData) end
                    end
                end
            end
        else
            local tempData = player:FormatEffectData(effData,playState)
            if tempData then table.insert(dataList,tempData) end
        end
    end

    local isNeedScale = effTarget == LFightConst.EFFECT_TO_SELF or effTarget == LFightConst.EFFECT_TO_EVERY_TAR

    if _isPosOnHook then
        local list = {}
        local effType = effData.effType
        for i,v in ipairs(dataList) do
            local tarId = v.tarId
            if not string.isempty(tarId) then
                local tempTab = _recordPosOnHookIdMap[tarId]
                if not tempTab or not tempTab[effType] then
                    if not tempTab then
                        tempTab = {}
                        _recordPosOnHookIdMap[tarId] = tempTab
                    end
                    tempTab[effType] = true
                    table.insert(list,v)
                    break
                end
            end
        end
        if #list > 0 then
            dataList = list
        end
    end


    local targetObj = nil
    local boneName = effData.boneName
    if not string.isempty(boneName) then
        targetObj = player:GetTargetAtkUnitView()
    end

    local offsetX = offset.x
    local offsetY = offset.y
    local offsetZ = offset.z or 0

    local effectCtrl = _viewMgr:GetEffectCtrl()
    for k, v in ipairs(dataList) do
        local pos = nil
        local dir = v.dir
        ---根据子弹落点
        if excursionIObject == 1 and playState.bulletTarPos then
            pos = playState.bulletTarPos
            pos.z = 0
        else

            pos = v.pos
            local offset = nil
            if dir == LFightConst.DIRECTION_LEFT then
                offset = Vector3.New(-offsetX,offsetY,offsetZ)
            else
                offset = Vector3.New(offsetX,offsetY,offsetZ)
            end

            if v.isLocal then
                pos = offset
            else
                pos = v.pos + offset
            end
            pos.z = offsetZ
        end

        local rootTrans = v.trans

        local scale = 1
        if rootTrans == _viewMgr:GetEffectRootTrans() then
            if isNeedScale then
                scale = player:GetScale()
                if scale > 1 then
                    pos.y = pos.y * scale
                end
            end
        end

        local localPos = v.isLocal and pos or nil
        local effect = effectCtrl:MakeBattleSkillEffectObj(rootTrans, effRes, pos, dir, 0, playTime,dissipateTime)
        local para = {
            isUpperLayer= player:IsUpperLayer(v.tarId),
            scale = scale,
            localPos = localPos,
            targetObj = targetObj,
            boneName = boneName,
        }
        effect:SetEffectPara(para)

        effectCtrl:AddEffect(effect)
    end
end

return LBattleSkillActEffect